/**
 * Normalizes a string for matching by removing spaces and special characters.
 */
const normalize = (str) => str.toLowerCase().replace(/[^a-z0-9]/g, '');

/**
 * Searches for an official book PDF link based on a search query.
 * Expects queries like "[subject] book" or "[subject] tamil medium book".
 * 
 * @param {string} query The user's search query
 * @returns {string|null} The URL of the official book PDF, or null if no match found.
 */
export function getOfficialBookUrl(query) {
  if (!query || query.length < 3) return null;
  
  const lowerQuery = query.toLowerCase().trim();
  
  // Clean up the query to extract the subject
  let subjectQuery = lowerQuery
    .replace(/\bbooks?\b/g, '')
    .replace(/\b(12th|10th|11th|std|standard)\b/g, '')
    .trim();

  // Map common abbreviations to full subject names
  subjectQuery = subjectQuery
    .replace(/\bmaths?\b/g, 'mathematics')
    .replace(/\bcomp sci\b|\bcs\b/g, 'computer science')
    .replace(/\bbio\b/g, 'biology')
    .replace(/\bphy\b/g, 'physics')
    .replace(/\bchem\b/g, 'chemistry')
    .replace(/\beco\b/g, 'economics')
    .replace(/\baccounts\b/g, 'accountancy')
    .replace(/\bcom\b/g, 'commerce');

  let medium = 'english'; // Default to English
  
  // Check if they specifically asked for tamil medium
  if (subjectQuery.includes('tamil medium') || subjectQuery.includes(' tm')) {
    medium = 'tamil';
    subjectQuery = subjectQuery.replace('tamil medium', '').replace(/\btm\b/g, '').trim();
  } else if (subjectQuery.includes('english medium') || subjectQuery.includes(' em')) {
    medium = 'english';
    subjectQuery = subjectQuery.replace('english medium', '').replace(/\bem\b/g, '').trim();
  }
  
  const normSubjectQuery = normalize(subjectQuery);
  
  if (normSubjectQuery.length < 3) return null; // Avoid matching empty/too generic strings after cleanup
  
  // Try exact match on normalized string first
  let match = officialBooks.find(b => b.medium === medium && b.normalizedSubject === normSubjectQuery);
  
  // If no exact match, try fuzzy match (if the book name contains the search query or vice versa)
  if (!match) {
    match = officialBooks.find(b => 
      b.medium === medium && 
      (b.normalizedSubject.includes(normSubjectQuery) || normSubjectQuery.includes(b.normalizedSubject))
    );
  }
  
  // Fallback: If they asked for english but we only have tamil, or vice versa
  if (!match) {
      match = officialBooks.find(b => b.normalizedSubject.includes(normSubjectQuery) || normSubjectQuery.includes(b.normalizedSubject));
  }
  
  return match ? match.url : null;
}
